import { Component, EventEmitter, Output } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { TaskService } from '../../services/task.service';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';

@Component({
  selector: 'app-task-form',
  templateUrl: './task-form.component.html',
  styleUrls: ['./task-form.component.css'],
})
export class TaskFormComponent {
  taskForm: FormGroup;
  @Output() completionStatusChange: EventEmitter<any> = new EventEmitter();

  constructor(
    private formBuilder: FormBuilder,
    private taskService: TaskService,
    private router: Router,
    private http: HttpClient
  ) {
    this.taskForm = this.formBuilder.group({
      title: ['', Validators.required],
      completed: [false],
      category: [''],
      dueDate: [''],
    });
  }

  addTask(): void {
    if (this.taskForm.valid) {
      const completionStatus = this.taskForm.get('completed')?.value || false;
      this.completionStatusChange.emit(completionStatus);

      this.taskService.addTask(this.taskForm.value).subscribe(() => {
        this.taskForm.reset({
          title: '',
          completed: false,
        });
      });
    }
  }
}
<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>Your Form Title</title>
    <style>
      body {
        display: flex;
        justify-content: center;
        align-items: center;
        height: 100vh;
        margin: 0;
        background-color: #f0f0f0; /* Set your desired background color */
      }

      form {
        width: 50%;
        background-color: #ffffff; /* Set your desired form background color */
        padding: 20px;
        box-shadow: 0 0 10px rgba(0, 0, 0, 0.1); /* Optional: Add a box shadow for a subtle effect */
      }

      div {
        margin-bottom: 15px;
      }

      label {
        display: block;
        margin-bottom: 5px;
        font-weight: bold;
      }

      input[type="checkbox"] {
        width: auto;
        margin-right: 5px;
      }

      button {
        padding: 10px;
        background-color: #4caf50; /* Set your desired button color */
        color: #ffffff; /* Set your desired button text color */
        border: none;
        cursor: pointer;
        position: center;
      }
    </style>
  </head>
  <body>
    <form [formGroup]="taskForm" (ngSubmit)="addTask()">
      <div>
        <label>Title:</label>
        <input formControlName="title" type="text" />
      </div>
      <div>
        <label>Completed:</label>
        <input formControlName="completed" type="checkbox" />
      </div>
      <div>
        <label>Category:</label>
        <input formControlName="category" type="text" />
      </div>
      <div>
        <label>Due Date:</label>
        <input formControlName="dueDate" type="date" />
      </div>
      <div>
        <button type="submit">Add Task</button>
      </div>
    </form>
  </body>
</html>
